function randomBetween(a: number, b: number) {
  return a + Math.random() * (b - a);
}

export default function RainBackground() {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const count = window.innerWidth >= 768 ? 16 : 8;
    const elements: HTMLDivElement[] = [];

    for (let i = 0; i < count; i++) {
      const wrapper = document.createElement("div");
      const scale = randomBetween(0.6, 1.4);
      wrapper.style.cssText = `
        position: absolute;
        top: -50px;
        opacity: 0;
        left: ${randomBetween(2, 95)}%;
        transform: scale(${scale}) rotate(${randomBetween(-15, 15)}deg);
        pointer-events: none;
      `;
      wrapper.innerHTML = `<svg width="34" height="35" viewBox="0 0 34 35" fill="none" xmlns="http://www.w3.org/2000/svg">${SVG_PATH}</svg>`;
      container.appendChild(wrapper);
      elements.push(wrapper);
    }

    function animateDrop(el: HTMLDivElement) {
      const duration = randomBetween(8, 16);
      const delay = randomBetween(0, 12);
      const vh = window.innerHeight;

      gsap.set(el, { top: -50, opacity: 0 });

      gsap.to(el, {
        top: vh + 20,
        duration,
        delay,
        ease: "none",
        onComplete: () => animateDrop(el),
      });

      gsap.to(el, {
        opacity: randomBetween(0.16, 0.32),
        duration: 1.2,
        delay,
        ease: "power1.in",
      });

      gsap.to(el, {
        opacity: 0,
        duration: duration * 0.28,
        delay: delay + duration * 0.72,
        ease: "power2.in",
      });
    }

    elements.forEach((el) => animateDrop(el));

    return () => {
      gsap.killTweensOf(elements);
      elements.forEach((el) => el.remove());
    };
  }, []);

  return (
    <div
      ref={containerRef}
      className="fixed inset-0 pointer-events-none overflow-hidden"
    />
  );
}
